import React, { useState } from "react";
import { theme, Card, Typography, Space, Descriptions, Tag, Tabs, Select, Button, Input, Divider, message, Flex, Empty } from "antd";
import { 
  DashboardOutlined, 
  InboxOutlined, 
  ControlOutlined, 
  EditOutlined, 
  UnlockOutlined, 
  BulbOutlined, 
  SyncOutlined 
} from "@ant-design/icons";
import { StorageInfo, mockStocks } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";

const { Title, Text } = Typography;

interface DetailPanelProps {
  item: StorageInfo | null;
  onRefresh?: (item: StorageInfo) => void;
}

export default function DetailPanel({ item, onRefresh }: DetailPanelProps) {
  const { token } = useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [editingStock, setEditingStock] = useState<any>(null);

  React.useEffect(() => {
    setEditingStock(null);
    setActiveTab("dashboard");
  }, [item]);

  // Control State
  const [fanMode, setFanMode] = useState("auto");
  const [lampMode, setLampMode] = useState("led1_on");

  if (!item) {
    return (
      <div style={{ height: "100%", display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", gap: 12 }}>
        <img src={`${import.meta.env.BASE_URL}assets/platforms/storageLocker/logo.png`} style={{ width: 80, opacity: 0.1, filter: "grayscale(1)" }} alt="placeholder" />
        <Text type="secondary">{t("storageLocker:dashboard.selectPlaceholder")}</Text>
      </div>
    );
  }

  const handleControl = (type: string, val: string) => {
    message.loading(`${item.name} - ${type} ${t("storageLocker:dashboard.ctrlProcessing")}`, 1);
    setTimeout(() => {
      message.success(`${item.name} - ${type} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      if (onRefresh) onRefresh(item);
    }, 1000);
  };

  const items = [
    {
      key: "dashboard",
      label: <span><DashboardOutlined /> {t("storageLocker:navigation.dashboard")}</span>,
      children: (
        <Space direction="vertical" style={{ width: "100%" }} size={16}>
          <Descriptions title={item.name} column={1} bordered size="small">
            <Descriptions.Item label={t("storageLocker:dashboard.connectStatus")}>
              <Tag color={item.connectState === "on" ? "success" : "error"}>
                {item.connectState === "on" ? t("storageLocker:dashboard.on").toUpperCase() : t("storageLocker:dashboard.off").toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label={t("storageLocker:dashboard.address")}>{item.address}</Descriptions.Item>
            <Descriptions.Item label={t("storageLocker:dashboard.tempHumi")}>{`${item.temperature}°C / ${item.humidity}%`}</Descriptions.Item>
          </Descriptions>
          <div style={{ height: 200, background: token.colorBgLayout, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Text type="secondary">[ {t("storageLocker:dashboard.tempHumi")} {t("common:chartArea")} ]</Text>
          </div>
        </Space>
      ),
    },
    {
      key: "inventory",
      label: <span><InboxOutlined /> {t("storageLocker:dashboard.inventoryTitle")}</span>,
      children: (
        <Space direction="vertical" style={{ width: "100%" }} size={16}>
          {editingStock && (
            <Card size="small" title={t("common:edit")} style={{ background: token.colorBgLayout }}>
              <Space direction="vertical" style={{ width: "100%" }}>
                <Input 
                  value={editingStock.itemNm} 
                  onChange={e => setEditingStock({...editingStock, itemNm: e.target.value})} 
                  placeholder={t("storageLocker:dashboard.lockerName")}
                />
                <Space>
                  <Text>{t("storageLocker:dashboard.status")}:</Text>
                  <Input 
                    type="number" 
                    value={editingStock.currentQty} 
                    onChange={e => setEditingStock({...editingStock, currentQty: parseInt(e.target.value) || 0})} 
                    style={{ width: 80 }}
                  />
                  <Button type="primary" onClick={() => {
                    message.success(`${editingStock.itemNm} ${t("storageLocker:dashboard.ctrlSuccess")}`);
                    setEditingStock(null);
                  }}>
                    {t("common:save")}
                  </Button>
                  <Button onClick={() => setEditingStock(null)}>{t("common:cancel")}</Button>
                </Space>
              </Space>
            </Card>
          )}
          <Flex vertical style={{ width: "100%" }}>
            {(mockStocks[item.id] || []).length > 0 ? (
              (mockStocks[item.id] || []).map((stock, idx) => (
                <div key={stock.itemNm + idx}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 4px" }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 600, fontSize: 13 }}>{stock.itemNm}</div>
                      <div style={{ color: token.colorTextSecondary, fontSize: 11 }}>
                        {t("storageLocker:dashboard.lastCheck")}: {stock.lastDt}
                      </div>
                    </div>
                    <Space>
                      <Tag color={stock.currentQty > 0 ? "blue" : "red"} style={{ margin: 0 }}>
                        {stock.currentQty} {t("storageLocker:dashboard.unit_ea")}
                      </Tag>
                      <Button type="text" size="small" icon={<EditOutlined />} onClick={() => setEditingStock(stock)} />
                    </Space>
                  </div>
                  {idx < (mockStocks[item.id] || []).length - 1 && <Divider style={{ margin: 0, opacity: 0.6 }} />}
                </div>
              ))
            ) : (
              <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description={t("common:noObjects")} />
            )}
          </Flex>
        </Space>
      ),
    },
    {
      key: "control",
      label: <span><ControlOutlined /> {t("storageLocker:navigation.control")}</span>,
      children: (
        <Space direction="vertical" style={{ width: "100%" }} size={20}>
          <div>
            <Text strong style={{ display: "block", marginBottom: 8 }}><SyncOutlined /> {t("storageLocker:dashboard.fan")}</Text>
            <Space.Compact style={{ width: "100%" }}>
              <Select 
                defaultValue="auto" 
                style={{ flex: 1 }} 
                onChange={setFanMode}
                options={[
                  { value: "auto", label: t("storageLocker:dashboard.auto") },
                  { value: "on", label: t("storageLocker:dashboard.on") },
                  { value: "off", label: t("storageLocker:dashboard.off") },
                ]} 
              />
              <Button type="primary" onClick={() => handleControl("Fan", fanMode)}>{t("storageLocker:dashboard.execution")}</Button>
            </Space.Compact>
          </div>
          <Divider style={{ margin: "8px 0" }} />
          <div>
            <Text strong style={{ display: "block", marginBottom: 8 }}><BulbOutlined /> {t("storageLocker:dashboard.lamp")}</Text>
            <Space.Compact style={{ width: "100%" }}>
              <Select 
                defaultValue="led1_on" 
                style={{ flex: 1 }} 
                onChange={setLampMode}
                options={[
                  { value: "led1_on", label: t("storageLocker:dashboard.led1_on") },
                  { value: "led1_off", label: t("storageLocker:dashboard.led1_off") },
                  { value: "all_on", label: t("storageLocker:dashboard.all_on") },
                ]} 
              />
              <Button type="primary" onClick={() => handleControl("Lamp", lampMode)}>{t("storageLocker:dashboard.execution")}</Button>
            </Space.Compact>
          </div>
          <Divider style={{ margin: "8px 0" }} />
          <div>
            <Text strong style={{ display: "block", marginBottom: 8 }}><UnlockOutlined /> {t("storageLocker:dashboard.lock")}</Text>
            <Button 
              danger 
              block 
              icon={<UnlockOutlined />} 
              onClick={() => handleControl("Lock", "release")}
            >
              {t("storageLocker:dashboard.lockRelease")}
            </Button>
          </div>
        </Space>
      ),
    },
    {
      key: "edit",
      label: <span><EditOutlined /></span>,
      children: (
        <Space direction="vertical" style={{ width: "100%" }}>
          <Text strong>{t("storageLocker:dashboard.memoTitle")}</Text>
          <Input.TextArea rows={4} placeholder={t("common:memoPlaceholder")} />
          <Button type="primary" block>{t("common:save")}</Button>
        </Space>
      ),
    },
  ];

  return (
    <Tabs 
      activeKey={activeTab} 
      onChange={setActiveTab} 
      items={items} 
      size="small" 
      style={{ height: "100%" }}
    />
  );
}

const { useToken } = theme;
